const express = require('express');
const session = require('express-session');
const crypto = require('crypto');
const axios = require('axios');
const { Issuer, generators } = require('openid-client');

const app = express();

// Configuration - use environment variables
const config = {
  issuerUrl: process.env.OIDC_ISSUER_URL,
  clientId: process.env.OIDC_CLIENT_ID,
  clientSecret: process.env.OIDC_CLIENT_SECRET,
  redirectUri: process.env.OIDC_REDIRECT_URI,
  sessionSecret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  port: process.env.PORT || 3000
};

// Session configuration
app.use(session({
  secret: config.sessionSecret,
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 3600000,
    sameSite: 'lax'
  }
}));

let oidcClient;

// Initialize OIDC client
async function initializeOIDC() {
  const issuer = await Issuer.discover(config.issuerUrl);
  
  oidcClient = new issuer.Client({
    client_id: config.clientId,
    client_secret: config.clientSecret,
    redirect_uris: [config.redirectUri],
    response_types: ['code'],
    token_endpoint_auth_method: 'client_secret_basic'
  });
}

// Login route
app.get('/login', (req, res) => {
  const codeVerifier = generators.codeVerifier();
  const codeChallenge = generators.codeChallenge(codeVerifier);
  const state = generators.state();
  const nonce = generators.nonce();

  req.session.codeVerifier = codeVerifier;
  req.session.state = state;
  req.session.nonce = nonce;

  const authorizationUrl = oidcClient.authorizationUrl({
    scope: 'openid email profile',
    code_challenge: codeChallenge,
    code_challenge_method: 'S256',
    state: state,
    nonce: nonce
  });

  res.redirect(authorizationUrl);
});

// Callback route
app.get('/callback', async (req, res) => {
  try {
    const params = oidcClient.callbackParams(req);
    
    // Validate state parameter
    if (!req.session.state || params.state !== req.session.state) {
      return res.status(403).send('Invalid state parameter');
    }

    // Exchange authorization code for tokens with PKCE
    const tokenSet = await oidcClient.callback(
      config.redirectUri,
      params,
      {
        code_verifier: req.session.codeVerifier,
        state: req.session.state,
        nonce: req.session.nonce
      }
    );

    // CRITICAL: Validate ID token using openid-client's built-in validation
    // This performs signature verification, issuer validation, audience validation,
    // expiration checks, and nonce validation
    const claims = tokenSet.claims();

    // Additional validation
    if (!claims.sub) {
      return res.status(403).send('Invalid token: missing subject');
    }

    // Verify nonce matches
    if (claims.nonce !== req.session.nonce) {
      return res.status(403).send('Invalid nonce');
    }

    // Optional: Verify token at userinfo endpoint for additional validation
    const userinfo = await oidcClient.userinfo(tokenSet.access_token);

    // Verify subject consistency
    if (userinfo.sub !== claims.sub) {
      return res.status(403).send('Subject mismatch between ID token and userinfo');
    }

    // Create secure session with validated claims
    req.session.regenerate((err) => {
      if (err) {
        return res.status(500).send('Session error');
      }

      req.session.user = {
        sub: claims.sub,
        email: claims.email || userinfo.email,
        name: claims.name || userinfo.name,
        email_verified: claims.email_verified || userinfo.email_verified
      };

      // Store tokens securely (encrypted in production)
      req.session.tokens = {
        access_token: tokenSet.access_token,
        refresh_token: tokenSet.refresh_token,
        expires_at: tokenSet.expires_at
      };

      // Clear temporary session data
      delete req.session.codeVerifier;
      delete req.session.state;
      delete req.session.nonce;

      res.redirect('/profile');
    });

  } catch (error) {
    console.error('Authentication error:', error.message);
    res.status(401).send('Authentication failed');
  }
});

// Protected route
app.get('/profile', (req, res) => {
  if (!req.session.user) {
    return res.redirect('/login');
  }

  res.json({
    message: 'User profile',
    user: req.session.user
  });
});

// Logout route
app.get('/logout', async (req, res) => {
  const idTokenHint = req.session.tokens?.id_token;
  
  req.session.destroy((err) => {
    if (err) {
      console.error('Logout error:', err);
    }

    const logoutUrl = oidcClient.endSessionUrl({
      id_token_hint: idTokenHint,
      post_logout_redirect_uri: process.env.POST_LOGOUT_REDIRECT_URI
    });

    res.redirect(logoutUrl || '/');
  });
});

// Home route
app.get('/', (req, res) => {
  res.send(`
    <h1>OIDC Authentication Demo</h1>
    ${req.session.user 
      ? `<p>Logged in as: ${req.session.user.email}</p><a href="/profile">Profile</a> | <a href="/logout">Logout</a>`
      : '<a href="/login">Login</a>'
    }
  `);
});

// Start server
